import ast, subprocess

def docstring_owners(src):
    tree = ast.parse(src)
    owners = {}  # qualname -> docstring
    def walk(node, prefix=""):
        for child in ast.iter_child_nodes(node):
            if isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                q = prefix + child.name
                ds = ast.get_docstring(child, clean=False)
                owners[q] = ds
                walk(child, q + ".")
        # module docstring
    md = ast.get_docstring(tree, clean=False)
    if md is not None:
        owners["<module>"] = md
    return owners

