import ast, subprocess

def owners(src):
    tree = ast.parse(src)
    o = {}
    for parent in ast.walk(tree):
        for child in ast.iter_child_nodes(parent):
            if isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                # build a semi-qualified key: name + lineno to disambiguate
                key = f"{child.name}@{child.lineno}"
                o[key] = (child.name, ast.get_docstring(child, clean=False))
    md = ast.get_docstring(tree, clean=False)
    if md is not None:
        o["<module>@0"] = ("<module>", md)
    return o

files = subprocess.check_output(["git","diff","--name-only","--","src/"], text=True).split()
total_new = 0
per_file = {}
new_symbols = []
for f in files:
    head = owners(subprocess.check_output(["git","show",f"HEAD:{f}"], text=True))
    work = owners(open(f).read())
    # Match by name (lineno shifts). Count names whose docstring went None->str.
    head_by_name = {}
    for k,(name,ds) in head.items():
        head_by_name.setdefault(name, []).append(ds)
    added = []
